#!/usr/bin/env bash\nset -euo pipefail\n\n# РЈСЃС‚Р°РЅРѕРІРєР° GitHub Copilot CLI (РїСЂРѕРїСЂРёРµС‚Р°СЂРЅС‹Р№ РёРЅСЃС‚СЂСѓРјРµРЅС‚, С‚СЂРµР±СѓРµС‚ GitHub-Р°РєРєР°СѓРЅС‚ Рё РїРѕРґРїРёСЃРєСѓ).\n\nif [[ $EUID -ne 0 ]]; then\n  echo "РџРѕР¶Р°Р»СѓР№СЃС‚Р°, Р·Р°РїСѓСЃС‚РёС‚Рµ СЌС‚РѕС‚ СЃРєСЂРёРїС‚ СЃ sudo РёР»Рё РѕС‚ root (РґР»СЏ СЃРёСЃС‚РµРјРЅС‹С… РїР°РєРµС‚РѕРІ)."\n  exit 1\nfi\n\necho "[install-github-copilot-cli] РЈСЃС‚Р°РЅРѕРІРєР° Node.js Рё npm (РµСЃР»Рё РЅСѓР¶РЅРѕ)..."\napt-get update -y\nDEBIAN_FRONTEND=noninteractive apt-get install -y nodejs npm ca-certificates\n\necho "[install-github-copilot-cli] РЈСЃС‚Р°РЅРѕРІРєР° @githubnext/github-copilot-cli РіР»РѕР±Р°Р»СЊРЅРѕ..."\nnpm install -g @githubnext/github-copilot-cli || {\n  echo "[install-github-copilot-cli] РќРµ СѓРґР°Р»РѕСЃСЊ СѓСЃС‚Р°РЅРѕРІРёС‚СЊ GitHub Copilot CLI С‡РµСЂРµР· npm."\n  exit 1\n}\n\ncat <<'EOF'\n[install-github-copilot-cli] Р“РѕС‚РѕРІРѕ.\n\nР”Р°Р»СЊРЅРµР№С€РёРµ С€Р°РіРё:\n  1. Р’РѕР№С‚Рё РІ GitHub РёР· CLI (Р±СѓРґРµС‚ РїСЂРµРґР»РѕР¶РµРЅР° Р°РІС‚РѕСЂРёР·Р°С†РёСЏ РїСЂРё РїРµСЂРІРѕРј Р·Р°РїСѓСЃРєРµ).\n  2. РЈР±РµРґРёС‚СЊСЃСЏ, С‡С‚Рѕ Сѓ Р°РєРєР°СѓРЅС‚Р° РµСЃС‚СЊ РґРѕСЃС‚СѓРї Рє GitHub Copilot.\n  3. РСЃРїРѕР»СЊР·РѕРІР°С‚СЊ РєРѕРјР°РЅРґС‹ РІРёРґР°:\n     github-copilot-cli git-assist\n     github-copilot-cli explain "РєРѕРјР°РЅРґР°"\nEOF\n\n